// Парсер с state machine: idle/photos/names/confirm/running
const sd = $getWorkflowStaticData('global');
const update = $input.first().json;
const chatId = update.message?.chat?.id;
const text = update.message?.text;

if (!chatId) {
  return [{ json: { complete: false, prompt_text: null, chatId: null, products: [], photos: [], skip: true } }];
}

sd.sessions = sd.sessions || {};
sd.sessions[chatId] = sd.sessions[chatId] || { phase: 'idle', photos: [], products: [], started_at: Date.now() };
const s = sd.sessions[chatId];
const trimmed = (text || '').trim();

const KB_IDLE = {
  keyboard: [
    [{text:'\u{1F680} Новая партия'}],
    [{text:'\u{1F4F8} Этап 1: Фото'},{text:'\u{1F4C2} Этап 2: Категории'}],
    [{text:'\u{270F}\u{FE0F} Этап 3: Карточки'},{text:'\u{1F69A} Этап 4: Заливка'}],
    [{text:'\u{1F4CA} Статус'},{text:'\u{2139}\u{FE0F} Помощь'}]
  ],
  resize_keyboard: true, is_persistent: true
};
const KB_PHOTOS = {
  keyboard: [
    [{text:'\u{2705} Перейти к названиям'}],
    [{text:'\u{1F4CA} Статус'},{text:'\u{2139}\u{FE0F} Помощь'}],
    [{text:'\u{1F504} Сбросить'}]
  ],
  resize_keyboard: true, is_persistent: true
};
const KB_NAMES = {
  keyboard: [
    [{text:'\u{1F504} Сбросить'},{text:'\u{2139}\u{FE0F} Помощь'}]
  ],
  resize_keyboard: true, is_persistent: true
};
const KB_CONFIRM = {
  keyboard: [
    [{text:'\u{1F680} Генерация'},{text:'\u{274C} Отмена'}]
  ],
  resize_keyboard: true, is_persistent: true
};

function reply(textMsg, kb) {
  return [{ json: {
    complete: false, chatId, products: [], photos: [],
    prompt_text: textMsg, skip: false, keyboard: kb
  }}];
}
function summary(s) {
  if (!s.products.length) return '_список пуст_';
  return s.products.map((p, i) => `${i+1}) ${p.name} \`${p.sku}\``).join('\n');
}

// Универсальные команды (работают в любой фазе)
if (trimmed === '/reset' || trimmed === '\u{1F504} Сбросить' || trimmed === '\u{274C} Отмена') {
  sd.sessions[chatId] = { phase: 'idle', photos: [], products: [], started_at: Date.now() };
  return reply('\u{1F9F9} *Сессия сброшена.* Жми «🚀 Новая партия» для запуска.', KB_IDLE);
}
if (trimmed === '/help' || trimmed === '\u{2139}\u{FE0F} Помощь') {
  return reply(
    '*Помощь.*\n\n' +
    'Сценарий:\n' +
    '1) Жми «🚀 Новая партия»\n' +
    '2) Кидай фото товаров — *по одному*. После каждого пишу «фото N принято».\n' +
    '3) Когда все фото загружены — жми «✅ Перейти к названиям».\n' +
    '4) Для каждого фото пиши `Название, артикул` (по одной строке за раз).\n' +
    '5) После всех названий покажу свод. Жми «🚀 Генерация» для старта или «❌ Отмена» для сброса.\n\n' +
    'Команды: `/reset` `/status` `/help`',
    s.phase === 'photos' ? KB_PHOTOS : (s.phase === 'names' ? KB_NAMES : (s.phase === 'confirm' ? KB_CONFIRM : KB_IDLE))
  );
}
if (trimmed === '/status' || trimmed === '\u{1F4CA} Статус') {
  const fazaText = ({
    'idle':'_ожидание (жми Новая партия)_',
    'photos':'*приём фото*',
    'names':'*приём названий*',
    'confirm':'*ожидание подтверждения*',
    'running':'*пайплайн выполняется*'
  })[s.phase] || s.phase;
  return reply(
    `*Статус сессии:*\n` +
    `• Фаза: ${fazaText}\n` +
    `• Фото принято: *${s.photos.length}*\n` +
    `• Названий принято: *${s.products.length}*\n\n` +
    summary(s),
    s.phase === 'photos' ? KB_PHOTOS : (s.phase === 'names' ? KB_NAMES : (s.phase === 'confirm' ? KB_CONFIRM : KB_IDLE))
  );
}

// Info-кнопки этапов (работают в idle, иначе игнор)
if (trimmed === '\u{1F4F8} Этап 1: Фото') {
  return reply('\u{1F4F8} *Этап 1 — Генерация фото (ТЗ §3).*\n\nДля каждого товара 4 фото 3:4 через kie.ai gpt-image-2-i2i:\n• Главное (бренд + категория + 2-3 преимущества + плашка)\n• Набор 2 шт (тот же стиль)\n• Набор 3 шт (тот же стиль)\n• Доп.фото — инфографика\n\nДоп.фото идёт во *все 3 SKU*. Хранилище: Yandex Object Storage.', KB_IDLE);
}
if (trimmed === '\u{1F4C2} Этап 2: Категории') {
  return reply('\u{1F4C2} *Этап 2 — Категории (ТЗ §4).*\n\nПодбор категории Ozon+WB через LLM gpt-5-2 + дерево категорий маркетплейсов. Скачивание Excel-шаблона Ozon (1 на категорию). Считывание справочников полей.', KB_IDLE);
}
if (trimmed === '\u{270F}\u{FE0F} Этап 3: Карточки') {
  return reply('\u{270F}\u{FE0F} *Этап 3 — Заполнение (ТЗ §5).*\n\n• 3 SKU/товар (одиночка, x2, x3)\n• Габариты +1 см если данные не точные\n• Названия Ozon: без дефиса, наборам префикс\n• WB: краткое без бренда, полное с брендом, ≤60\n• Состав WB ≤100\n• Аннотация Ozon ≥6 предложений\n• НДС 22%, штрихкоды пусто\n• Справочники: только из перечня; мультивыбор через `;`', KB_IDLE);
}
if (trimmed === '\u{1F69A} Этап 4: Заливка') {
  return reply('\u{1F69A} *Этап 4 — Заливка через API (ТЗ §6).*\n\n• Ozon: `POST /v3/product/import` + `/import/info`\n• WB: `POST /content/v2/cards/upload` + `/upload/list`\n\nОшибка одного SKU не валит партию. В конце Markdown-отчёт.', KB_IDLE);
}

// === STATE MACHINE ===
// idle -> photos
if (trimmed === '/start' || trimmed === '\u{1F680} Новая партия') {
  s.phase = 'photos';
  s.photos = []; s.products = [];
  return reply(
    '\u{1F44B} *Контент-завод. Новая партия.*\n\n' +
    'Кидай фото товаров *по одному*. После каждого фото я отвечу что принял.\n' +
    'Когда все фото загружены — жми «✅ Перейти к названиям».',
    KB_PHOTOS
  );
}

// PHASE: photos
if (s.phase === 'photos') {
  if (update.message?.photo?.length) {
    const biggest = update.message.photo[update.message.photo.length - 1];
    s.photos.push({ file_id: biggest.file_id, idx: s.photos.length });
    return reply(
      `\u{1F4F8} *Фото ${s.photos.length} принято.*\n\n` +
      `Пришли следующее фото или жми «✅ Перейти к названиям» (фото нельзя будет добавить позже).`,
      KB_PHOTOS
    );
  }
  if (trimmed === '\u{2705} Перейти к названиям') {
    if (s.photos.length === 0) {
      return reply('Сначала пришли хотя бы одно фото.', KB_PHOTOS);
    }
    if (s.photos.length > 10) {
      return reply(`Максимум 10 товаров за партию. У тебя ${s.photos.length} фото — слишком много. Жми «🔄 Сбросить» и начни заново.`, KB_PHOTOS);
    }
    s.phase = 'names';
    s.products = [];
    return reply(
      `\u{2705} *Принято ${s.photos.length} фото.*\n\n` +
      `Теперь пришли название и артикул для *фото №1*.\n` +
      `Формат: \`Название, артикул\` (через запятую).`,
      KB_NAMES
    );
  }
  if (text) {
    return reply('Сейчас фаза *приёма фото*. Пришли фотографию или жми «✅ Перейти к названиям».', KB_PHOTOS);
  }
  return reply('Жду фото.', KB_PHOTOS);
}

// PHASE: names
if (s.phase === 'names') {
  if (update.message?.photo?.length) {
    return reply('Сейчас фаза *приёма названий*. Фото добавлять нельзя. Если ошибся — жми «🔄 Сбросить».', KB_NAMES);
  }
  if (text) {
    const parts = text.split(/[,;\t]/).map(x => (x || '').trim()).filter(Boolean);
    if (parts.length < 2) {
      return reply('Неверный формат. Напиши: `Название, артикул` (через запятую). Например: `Кофе зерновой Арабика 250г, COF-001`', KB_NAMES);
    }
    const name = parts.slice(0, -1).join(', '); // если в названии есть запятые — собираем обратно
    const sku = parts[parts.length - 1];
    s.products.push({ name, sku, idx: s.products.length });
    const next = s.products.length;
    if (next < s.photos.length) {
      return reply(
        `\u{2714}\u{FE0F} *Фото ${next}:* ${name} \`${sku}\`\n\n` +
        `Теперь название+артикул для *фото №${next + 1}*:`,
        KB_NAMES
      );
    } else {
      // Все названия введены — переход к confirm
      s.phase = 'confirm';
      return reply(
        '\u{1F4DD} *Партия готова к генерации:*\n\n' +
        s.products.map((p, i) => `${i+1}) ${p.name} \`${p.sku}\``).join('\n') +
        '\n\nВсего: *' + s.products.length + ' товаров* × 4 фото = *' + (s.products.length * 4) + ' изображений*.\n\n' +
        'Жми «🚀 Генерация» чтобы запустить пайплайн (~3-5 мин на товар).\n' +
        'Или «❌ Отмена» чтобы сбросить.',
        KB_CONFIRM
      );
    }
  }
  return reply('Жду название+артикул.', KB_NAMES);
}

// PHASE: confirm
if (s.phase === 'confirm') {
  if (trimmed === '\u{1F680} Генерация') {
    // Старт пайплайна!
    s.phase = 'running';
    const products = s.products.map((p, i) => ({
      idx: i, sku: p.sku, name: p.name,
      photo: { file_id: s.photos[i].file_id, tg_file_path: null },
      brand: null, dims: null, weight: null
    }));
    const out_products = products;
    // очищаем состояние
    sd.sessions[chatId] = { phase: 'idle', photos: [], products: [], started_at: Date.now() };
    return [{ json: {
      complete: true, chatId,
      products: out_products,
      photos: s.photos,
      skip: false, keyboard: KB_IDLE,
      prompt_text: null
    }}];
  }
  if (trimmed === '\u{274C} Отмена') {
    sd.sessions[chatId] = { phase: 'idle', photos: [], products: [], started_at: Date.now() };
    return reply('\u{274C} *Отменено.* Жми «🚀 Новая партия» для нового запуска.', KB_IDLE);
  }
  return reply('Жми «🚀 Генерация» или «❌ Отмена».', KB_CONFIRM);
}

// PHASE: running — игнор всего
if (s.phase === 'running') {
  return reply('\u{23F3} Пайплайн уже выполняется. Жди отчёт. Если хочешь прервать — жми «🔄 Сбросить» (но это не остановит уже запущенные API-вызовы).',
    {
      keyboard: [[{text:'\u{1F504} Сбросить'},{text:'\u{1F4CA} Статус'}]],
      resize_keyboard: true, is_persistent: true
    }
  );
}

// fallback
return reply('Не понял. Жми «ℹ️ Помощь».', KB_IDLE);

