// 0.5 — Сборка канонического batch для Модуля 1
const data = $input.first().json;

const batch = {
  batch_id: `${Date.now().toString(36)}-${Math.random().toString(36).slice(2, 8)}`,
  chatId: data.chatId,
  products: data.products.map((p, i) => ({
    idx: i,
    sku: p.sku,
    name: p.name,
    photo: { file_id: data.photos[i]?.file_id || null, tg_file_path: null },
    brand: null,
    dims: null,
    weight: null
  })),
  created_at: new Date().toISOString()
};

return [{ json: { batch } }];

// 0.99 — Подготовка текста критической ошибки (без $env)
const err = $input.first().json;
const exec = err.execution || {};
const wf = err.workflow || {};
const e = err.execution?.error || err.error || {};
const msg = (e.message || JSON.stringify(e) || 'неизвестная ошибка').toString().slice(0, 800);
const nodeName = e.node?.name || '—';
const stack = (e.stack || '').toString().slice(0, 300);
const chatId = err.execution?.input?.chatId
             || err.execution?.input?.batch?.chatId
             || null;
return [{ json: {
  chatId,
  text: `❌ *Ошибка в воркфлоу* \`${wf.name || ''}\`\nНода: \`${nodeName}\`\n\n${msg}\n\n${stack}`
}}];

// Преобразуем batch в формат для Python /api/run
const batch = $input.first().json.batch;
const products = (batch.products || []).map((p, i) => ({
  idx: typeof p.idx === 'number' ? p.idx : i,
  sku: p.sku,
  name: p.name,
  tg_file_id: p.photo?.file_id || null,
  brand: p.brand || null,
}));
return [{ json: {
  batch_id: batch.batch_id,
  chat_id: batch.chatId,
  products
}}];

